import React, { useState, useEffect } from 'react';
import './NewReservation.css';

const NewReservation = () => {
  const [cinemas, setCinemas] = useState([]);
  const [loading, setLoading] = useState(true);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [currentStep, setCurrentStep] = useState(1);
  const [errors, setErrors] = useState({});
  const [notification, setNotification] = useState({
    show: false,
    message: "",
    type: "success"
  });

  const [formData, setFormData] = useState({
    selectedCinema: null,
    selectedMovie: null,
    selectedSlots: [],
    customerInfo: {
      name: '',
      email: '',
      phone: ''
    }
  });

  const totalSteps = 5;

  const steps = [
    { id: 1, title: 'Select Cinema', description: 'Choose cinema location' },
    { id: 2, title: 'Select Movie', description: 'Choose movie and view slots' },
    { id: 3, title: 'Select Slots', description: 'Choose advertisement slots' },
    { id: 4, title: 'Summary', description: 'Review your selection' },
    { id: 5, title: 'Confirmation', description: 'Complete reservation' }
  ];

  // Fetch cinemas from API
  const fetchCinemas = async () => {
    try {
      setLoading(true);
      console.log('🔍 Fetching cinemas from API...');
      const response = await fetch('http://localhost:5000/api/cinemas');
      console.log('📡 Response status:', response.status);
      
      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }
      
      const data = await response.json();
      console.log('📊 Received data:', data);
      
      if (data.success) {
        setCinemas(data.data);
        console.log('✅ Cinemas loaded successfully:', data.data.length);
      } else {
        console.error('❌ API returned error:', data.message);
        showNotification('Failed to fetch cinemas', 'error');
      }
    } catch (error) {
      console.error('❌ Error fetching cinemas:', error);
      showNotification(`Error fetching cinemas: ${error.message}`, 'error');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchCinemas();
  }, []);

  const showNotification = (message, type = 'success') => {
    setNotification({ show: true, message, type });
    setTimeout(() => {
      setNotification({ ...notification, show: false });
    }, 5000);
  };

  const closeNotification = () => {
    setNotification({ ...notification, show: false });
  };

  // Extract YouTube video ID from URL
  const getYouTubeVideoId = (url) => {
    if (!url) return null;
    const regExp = /^.*(youtu.be\/|v\/|u\/\w\/|embed\/|watch\?v=|&v=)([^#&?]*).*/;
    const match = url.match(regExp);
    return (match && match[2].length === 11) ? match[2] : null;
  };

  // Generate YouTube thumbnail URL
  const getYouTubeThumbnail = (url) => {
    const videoId = getYouTubeVideoId(url);
    return videoId ? `https://img.youtube.com/vi/${videoId}/mqdefault.jpg` : null;
  };

  // Generate Google Maps embed URL
  const getGoogleMapsEmbedUrl = (mapsUrl) => {
    if (!mapsUrl) return null;
    // Extract coordinates or place ID from Google Maps URL
    const match = mapsUrl.match(/@(-?\d+\.\d+),(-?\d+\.\d+)/);
    if (match) {
      const lat = match[1];
      const lng = match[2];
      return `https://www.google.com/maps/embed/v1/view?key=YOUR_API_KEY&center=${lat},${lng}&zoom=15&maptype=roadmap`;
    }
    return null;
  };

  const handleCinemaSelect = (cinema) => {
    setFormData(prev => ({
      ...prev,
      selectedCinema: cinema,
      selectedMovie: null,
      selectedSlots: []
    }));
    setCurrentStep(2);
  };

  const handleMovieSelect = (movieKey, movie) => {
    setFormData(prev => ({
      ...prev,
      selectedMovie: { key: movieKey, ...movie }
    }));
    setCurrentStep(3);
  };

  const handleSlotToggle = (slot) => {
    setFormData(prev => {
      const isSelected = prev.selectedSlots.some(s => s.slot_number === slot.slot_number);
      let newSelectedSlots;
      
      if (isSelected) {
        // Remove slot
        newSelectedSlots = prev.selectedSlots.filter(s => s.slot_number !== slot.slot_number);
      } else {
        // Add slot
        newSelectedSlots = [...prev.selectedSlots, slot];
      }
      
      return {
        ...prev,
        selectedSlots: newSelectedSlots
      };
    });
  };

  const calculateTotalPrice = () => {
    return formData.selectedSlots.reduce((total, slot) => total + slot.price, 0);
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    
    if (name.startsWith('customerInfo.')) {
      const field = name.split('.')[1];
      setFormData(prev => ({
        ...prev,
        customerInfo: {
          ...prev.customerInfo,
          [field]: value
        }
      }));
    }
  };

  const validateCurrentStep = () => {
    const newErrors = {};
    
    if (currentStep === 1) {
      if (!formData.selectedCinema) {
        newErrors.cinema = 'Please select a cinema';
      }
    } else if (currentStep === 2) {
      if (!formData.selectedMovie) {
        newErrors.movie = 'Please select a movie';
      }
    } else if (currentStep === 3) {
      if (formData.selectedSlots.length === 0) {
        newErrors.slots = 'Please select at least one slot';
      }
    } else if (currentStep === 4) {
      if (!formData.customerInfo.name.trim()) {
        newErrors.customerName = 'Customer name is required';
      }
      if (!formData.customerInfo.email.trim()) {
        newErrors.customerEmail = 'Customer email is required';
      }
      if (!formData.customerInfo.phone.trim()) {
        newErrors.customerPhone = 'Customer phone is required';
      }
    }
    
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleNext = () => {
    if (validateCurrentStep()) {
      setCurrentStep(prev => Math.min(prev + 1, totalSteps));
      setErrors({});
    }
  };

  const handlePrevious = () => {
    setCurrentStep(prev => Math.max(prev - 1, 1));
    setErrors({});
  };

  const handleSubmit = async () => {
    try {
      const response = await fetch(`http://localhost:5000/api/cinemas/${formData.selectedCinema._id}/reserve-slots`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          movie_key: formData.selectedMovie.key,
          slot_numbers: formData.selectedSlots.map(slot => slot.slot_number),
          customer_info: formData.customerInfo
        })
      });

      const data = await response.json();

      if (data.success) {
        showNotification('Reservation completed successfully!', 'success');
        console.log('Reservation successful:', data.data);
        setIsModalOpen(false);
        setFormData({
          selectedCinema: null,
          selectedMovie: null,
          selectedSlots: [],
          customerInfo: { name: '', email: '', phone: '' }
        });
        setCurrentStep(1);
        // Refresh cinemas to show updated slot availability
        fetchCinemas();
      } else {
        showNotification(data.message || 'Failed to complete reservation', 'error');
        console.error('Reservation failed:', data);
      }
    } catch (error) {
      console.error('Error completing reservation:', error);
      showNotification('Error completing reservation', 'error');
    }
  };

  const handleCreateNew = () => {
    setIsModalOpen(true);
    setCurrentStep(1);
  };

  return (
    <div className="new-reservation">
      <div className="page-header">
        <div className="container">
          <h1>New Reservation</h1>
          <p>Reserve advertisement slots for your business</p>
          <button 
            className="btn btn-primary create-btn"
            onClick={handleCreateNew}
          >
            <i className="fa fa-plus"></i> Make Reservation
          </button>
        </div>
      </div>

      <div className="content-section">
        <div className="container">
          {loading ? (
            <div className="loading-container">
              <div className="spinner"></div>
              <p>Loading cinemas...</p>
            </div>
          ) : (
            <div className="cinema-grid">
              {cinemas.map((cinema) => (
                <div key={cinema._id} className="cinema-card">
                  <div className="cinema-header">
                    <h3>{cinema.cinema_name}</h3>
                    <p className="cinema-location">
                      <i className="fa fa-map-marker"></i>
                      {cinema.cinema_location}
                    </p>
                  </div>
                  
                  {cinema.google_maps_location && (
                    <div className="cinema-map">
                      <iframe
                        src={getGoogleMapsEmbedUrl(cinema.google_maps_location)}
                        width="100%"
                        height="200"
                        style={{ border: 0 }}
                        allowFullScreen=""
                        loading="lazy"
                        referrerPolicy="no-referrer-when-downgrade"
                      ></iframe>
                    </div>
                  )}
                  
                  <div className="cinema-movies">
                    <h4>Available Movies</h4>
                    {cinema.ongoing_movies && Object.keys(cinema.ongoing_movies).map((movieKey) => {
                      const movie = cinema.ongoing_movies[movieKey];
                      if (!movie || !movie.name) return null;
                      
                      return (
                        <div key={movieKey} className="movie-item">
                          <div className="movie-info">
                            <h5>{movie.name}</h5>
                            <p>{movie.start_date} - {movie.end_date}</p>
                          </div>
                          {movie.trailer_link && (
                            <div className="movie-trailer">
                              <img 
                                src={getYouTubeThumbnail(movie.trailer_link)} 
                                alt={`${movie.name} trailer`}
                                className="trailer-thumbnail"
                              />
                            </div>
                          )}
                        </div>
                      );
                    })}
                  </div>
                  
                  <button 
                    className="btn btn-primary"
                    onClick={() => handleCinemaSelect(cinema)}
                  >
                    Select This Cinema
                  </button>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>

      {/* Modal for Reservation Process */}
      {isModalOpen && (
        <div className="modal-overlay">
          <div className="modal-container">
            <div className="modal-header">
              <h2>Make Reservation</h2>
              <button className="close-btn" onClick={() => setIsModalOpen(false)}>×</button>
            </div>
            
            <div className="modal-body">
              {/* Progress Bar */}
              <div className="progress-bar">
                {steps.map((step) => (
                  <div 
                    key={step.id} 
                    className={`progress-step ${currentStep >= step.id ? 'active' : ''} ${currentStep > step.id ? 'completed' : ''}`}
                  >
                    {currentStep > step.id ? '' : step.id}
                  </div>
                ))}
              </div>

              {/* Step Content */}
              <div className="step-content">
                {currentStep === 1 && (
                  <div className="step-content active">
                    <h4>Select Cinema</h4>
                    <p>Choose the cinema where you want to advertise</p>
                    {formData.selectedCinema && (
                      <div className="selected-cinema">
                        <h5>{formData.selectedCinema.cinema_name}</h5>
                        <p>{formData.selectedCinema.cinema_location}</p>
                      </div>
                    )}
                  </div>
                )}

                {currentStep === 2 && formData.selectedCinema && (
                  <div className="step-content active">
                    <h4>Select Movie</h4>
                    <p>Choose the movie for your advertisement</p>
                    <div className="movie-selection">
                      {formData.selectedCinema.ongoing_movies && Object.keys(formData.selectedCinema.ongoing_movies).map((movieKey) => {
                        const movie = formData.selectedCinema.ongoing_movies[movieKey];
                        if (!movie || !movie.name) return null;
                        
                        return (
                          <div 
                            key={movieKey} 
                            className={`movie-option ${formData.selectedMovie?.key === movieKey ? 'selected' : ''}`}
                            onClick={() => handleMovieSelect(movieKey, movie)}
                          >
                            <div className="movie-poster">
                              {movie.trailer_link && (
                                <img 
                                  src={getYouTubeThumbnail(movie.trailer_link)} 
                                  alt={`${movie.name} poster`}
                                />
                              )}
                            </div>
                            <div className="movie-details">
                              <h5>{movie.name}</h5>
                              <p>{movie.start_date} - {movie.end_date}</p>
                            </div>
                          </div>
                        );
                      })}
                    </div>
                  </div>
                )}

                {currentStep === 3 && formData.selectedMovie && (
                  <div className="step-content active">
                    <h4>Select Advertisement Slots</h4>
                    <p>Choose the slots you want to reserve for {formData.selectedMovie.name}</p>
                    <div className="slots-grid">
                      {formData.selectedCinema.movie_slot_pricing && 
                       formData.selectedCinema.movie_slot_pricing[formData.selectedMovie.key] && 
                       formData.selectedCinema.movie_slot_pricing[formData.selectedMovie.key].slots ? 
                        formData.selectedCinema.movie_slot_pricing[formData.selectedMovie.key].slots.map((slot) => (
                          <div 
                            key={slot.slot_number}
                            className={`slot-card ${slot.is_reserved ? 'reserved' : 'available'} ${formData.selectedSlots.some(s => s.slot_number === slot.slot_number) ? 'selected' : ''}`}
                            onClick={() => !slot.is_reserved && handleSlotToggle(slot)}
                          >
                            <div className="slot-number">Slot {slot.slot_number}</div>
                            <div className="slot-type">{slot.slot_type}</div>
                            <div className="slot-price">LKR {slot.price}</div>
                            <div className="slot-status">
                              {slot.is_reserved ? 'Reserved' : 'Available'}
                            </div>
                          </div>
                        )) : (
                          <div className="no-slots">
                            <p>No slots available for this movie. Please contact the cinema.</p>
                          </div>
                        )
                      }
                    </div>
                  </div>
                )}

                {currentStep === 4 && (
                  <div className="step-content active">
                    <h4>Customer Information</h4>
                    <div className="form-group">
                      <label>Full Name *</label>
                      <input
                        type="text"
                        name="customerInfo.name"
                        value={formData.customerInfo.name}
                        onChange={handleInputChange}
                        className={errors.customerName ? 'error' : ''}
                        placeholder="Enter your full name"
                      />
                      {errors.customerName && <span className="error-message">{errors.customerName}</span>}
                    </div>
                    
                    <div className="form-group">
                      <label>Email Address *</label>
                      <input
                        type="email"
                        name="customerInfo.email"
                        value={formData.customerInfo.email}
                        onChange={handleInputChange}
                        className={errors.customerEmail ? 'error' : ''}
                        placeholder="Enter your email"
                      />
                      {errors.customerEmail && <span className="error-message">{errors.customerEmail}</span>}
                    </div>
                    
                    <div className="form-group">
                      <label>Phone Number *</label>
                      <input
                        type="tel"
                        name="customerInfo.phone"
                        value={formData.customerInfo.phone}
                        onChange={handleInputChange}
                        className={errors.customerPhone ? 'error' : ''}
                        placeholder="Enter your phone number"
                      />
                      {errors.customerPhone && <span className="error-message">{errors.customerPhone}</span>}
                    </div>
                  </div>
                )}

                {currentStep === 5 && (
                  <div className="step-content active">
                    <h4>Reservation Summary</h4>
                    <div className="reservation-summary">
                      <div className="summary-item">
                        <strong>Cinema:</strong> {formData.selectedCinema?.cinema_name}
                      </div>
                      <div className="summary-item">
                        <strong>Movie:</strong> {formData.selectedMovie?.name}
                      </div>
                      <div className="summary-item">
                        <strong>Selected Slots:</strong> {formData.selectedSlots.length}
                      </div>
                      <div className="summary-item">
                        <strong>Total Price:</strong> LKR {calculateTotalPrice()}
                      </div>
                      <div className="summary-item">
                        <strong>Customer:</strong> {formData.customerInfo.name}
                      </div>
                    </div>
                  </div>
                )}
              </div>

              {/* Modal footer */}
              <div className="btn-group">
                <button 
                  className="btn btn-prev" 
                  onClick={handlePrevious}
                  disabled={currentStep === 1}
                >
                  Back
                </button>
                
                {currentStep < totalSteps ? (
                  <button 
                    className="btn btn-next" 
                    onClick={handleNext}
                  >
                    Continue
                  </button>
                ) : (
                  <button 
                    className="btn btn-submit" 
                    onClick={handleSubmit}
                  >
                    Complete Reservation
                  </button>
                )}
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Notification */}
      {notification.show && (
        <div className={`custom-notification ${notification.type}`}>
          <div className="notification-content">
            <span className="notification-message">{notification.message}</span>
            <button className="notification-close" onClick={closeNotification}>×</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default NewReservation;
